proc isExtendedPictographic*(cp: int32): bool =
  var lo = 0
  var hi = extendedPictographicTable.len - 1
  while lo <= hi:
    let mid = (lo + hi) shr 1
    if cp < extendedPictographicTable[mid].lo:
      hi = mid - 1
    elif cp > extendedPictographicTable[mid].hi:
      lo = mid + 1
    else:
      return true
  return false
